changeSet.sql:
INSERT INTO permissions (code, description, version, created_at, updated_at) VALUES ('PRODUCT_CREATE', 'Create and edit products', 0, now(), now()), ('PRODUCT_APPROVE', 'Approve and manage product status', 0, now(), now());
INSERT INTO role_permissions (role_id, permission_id, version, created_at, updated_at) SELECT r.id, p.id, 0, now(), now() FROM roles r JOIN permissions p ON p.code IN ('PRODUCT_CREATE','PRODUCT_APPROVE') WHERE r.name = 'ADMIN';
INSERT INTO role_permissions (role_id, permission_id, version, created_at, updated_at) SELECT r.id, p.id, 0, now(), now() FROM roles r JOIN permissions p ON p.code = 'PRODUCT_APPROVE' WHERE r.name = 'QA_MANAGER';
INSERT INTO role_permissions (role_id, permission_id, version, created_at, updated_at) SELECT r.id, p.id, 0, now(), now() FROM roles r JOIN permissions p ON p.code = 'PRODUCT_CREATE' WHERE r.name = 'AUTHOR';

rollback.sql:
DELETE FROM role_permissions WHERE permission_id IN
    (SELECT id FROM permissions WHERE code IN ('PRODUCT_CREATE','PRODUCT_APPROVE'));
DELETE FROM permissions WHERE code IN ('PRODUCT_CREATE','PRODUCT_APPROVE');
